// Prepara los textos en espanol a traducir, respetando 'revisado'
const row = $json.body.data || $json.body.rows?.[0] || $json.body;
const campos = ['titulo','texto'];
const idiomas = ['EN','FR','DE'];
const tareas = [];
for (const c of campos) {
  const es = row[c+'_es'];
  if (!es) continue;
  for (const i of idiomas) {
    const rev = row['revisado_'+i.toLowerCase()];
    if (rev) continue; // no pisar traducciones revisadas a mano
    tareas.push({ id: row.id || row.Id, campo: c, idioma: i, texto: es });
  }
}
return tareas.map(t => ({json:t}));

